#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

__kernel void lud_diagonal(__global float *a,
                           __local float *shadow,
                           const int size,
                           const int offset)
{
    const int tx = (int)get_local_id(0);

    if (tx == 0) {
        int i, j, k;

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                shadow[i * BLOCK_SIZE + j] = a[(offset + i) * size + (offset + j)];
            }
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = i; j < BLOCK_SIZE; j++) {
                for (k = 0; k < i; k++) {
                    shadow[i * BLOCK_SIZE + j] -=
                        shadow[i * BLOCK_SIZE + k] * shadow[k * BLOCK_SIZE + j];
                }
            }

            {
                float temp = 1.0f / shadow[i * BLOCK_SIZE + i];
                for (j = i + 1; j < BLOCK_SIZE; j++) {
                    for (k = 0; k < i; k++) {
                        shadow[j * BLOCK_SIZE + i] -=
                            shadow[j * BLOCK_SIZE + k] * shadow[k * BLOCK_SIZE + i];
                    }
                    shadow[j * BLOCK_SIZE + i] *= temp;
                }
            }
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                a[(offset + i) * size + (offset + j)] = shadow[i * BLOCK_SIZE + j];
            }
        }
    }
}

__kernel void lud_perimeter(__global float *a,
                            __local float *temp_diag,
                            __local float *temp_top,
                            __local float *temp_left,
                            const int size,
                            const int offset)
{
    const int lid = (int)get_local_id(0);
    const int group = (int)get_group_id(0);

    if (lid == 0) {
        int i, j, k;
        int block = offset + BLOCK_SIZE * (group + 1);

        for (j = 0; j < BLOCK_SIZE; j++) {
            for (i = 0; i < BLOCK_SIZE; i++) {
                float sum = 0.0f;
                for (k = 0; k < i; k++) {
                    sum += a[(offset + i) * size + (offset + k)] *
                           a[(offset + k) * size + (block + j)];
                }
                a[(offset + i) * size + (block + j)] -= sum;
            }
        }

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (k = 0; k < j; k++) {
                    sum += a[(block + i) * size + (offset + k)] *
                           a[(offset + k) * size + (offset + j)];
                }
                a[(block + i) * size + (offset + j)] =
                    (a[(block + i) * size + (offset + j)] - sum) /
                    a[(offset + j) * size + (offset + j)];
            }
        }
    }
}

__kernel void lud_internal(__global float *a,
                           __local float *temp_top,
                           __local float *temp_left,
                           const int size,
                           const int offset)
{
    const int lx = (int)get_local_id(0);
    const int ly = (int)get_local_id(1);
    const int gx = (int)get_group_id(0);
    const int gy = (int)get_group_id(1);

    if (lx == 0 && ly == 0) {
        int i, j, k;
        int row = offset + BLOCK_SIZE * (gy + 1);
        int col = offset + BLOCK_SIZE * (gx + 1);

        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (k = 0; k < BLOCK_SIZE; k++) {
                    sum += a[(row + i) * size + (offset + k)] *
                           a[(offset + k) * size + (col + j)];
                }
                a[(row + i) * size + (col + j)] -= sum;
            }
        }
    }
}
